import java.util.Scanner;
import java.util.Arrays;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Define a maximum buffer size
        int bufferSize = 10;

        // Truncate or pad the input string to fit within the buffer size
        char[] buffer = Arrays.copyOf(name.toCharArray(), bufferSize);

        System.out.println("Hello, " + new String(buffer));
    }
}

